var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"물리적인 손상. 면역.","JPN":"物理的な損傷。免疫。","ENG":"Physical damage, Immune.","TWN":"物理損傷，免疫。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"TWN":"物理損傷，免疫。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_ICE_GRA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"공간 동결 후 붕괴. 면역.","JPN":"空間凍結後崩壊。免疫。","ENG":"Space freeze and collapsing. Immune.","TWN":"空間凍結後崩壞，免疫。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"TWN":"空間凍結後崩壞，免疫。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_INK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"분자 운동 동결. 면역.","JPN":"分子運動凍結。免疫。","ENG":"Molecular motion freeze. Immune.","TWN":"分子運動凍結，免疫。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"TWN":"分子運動凍結，免疫。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_INK_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"정보 확산 동결. 면역.","JPN":"情報拡散凍結。免疫。","ENG":"Informational spread freeze. Immune.","TWN":"資訊擴散凍結，免疫。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"TWN":"資訊擴散凍結，免疫。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_INK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"인지 능력 동결. 면역.","JPN":"認知能力凍結。免疫。","ENG":"Cognitive ability freeze. Immune.","TWN":"認知能力凍結，免疫。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"TWN":"認知能力凍結，免疫。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_ICE_GRA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"화학 반응 동결. 면역.","JPN":"化学反応凍結。免疫。","ENG":"Chemical reaction freeze. Immune.","TWN":"化學反應凍結，免疫。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"면역. 면역. 면역. 면역─","JPN":"免疫。免疫。免疫。免疫……","ENG":"Immune. Immune. Immune. Immune–","TWN":"免疫，免疫，免疫，免疫——"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>이제 만족하시나요, 레지나 님?</color>","JPN":"<color=#ff3636>もう満足されましたか？　レジーナ様。</color>","ENG":"<color=#ff3636>Are you satisfied now, Miss Regina?</color>","TWN":"<color=#ff3636>現在你滿意了嗎，蕾佳娜？</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>저희의 본질에 이렇게까지 근접하고도 정신이 온전한 인간은 레지나 님이 처음이에요.</color>","JPN":"<color=#ff3636>我々の本質にこれほどまで近づいて、精神が崩れなかった人間はレジーナ様が初めてです。</color>","ENG":"<color=#ff3636>You are the first person to have come this close to our essence while remaining sane.</color>","TWN":"<color=#ff3636>蕾佳娜是第一個如此接近我們的本質卻還精神正常的人。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>하지만 레지나 님은 가엾게도, 세계에 선택받지 못한 인간.</color>","JPN":"<color=#ff3636>ですがレジーナ様は哀れにも、世界に選ばれなかった人間。</color>","ENG":"<color=#ff3636>Unfortunately, Miss Regina... You are a human who is not chosen by the world.</color>","TWN":"<color=#ff3636>但可惜的是，蕾佳娜不是被世界選中的人。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>신이 만든 규칙을 뛰어넘지 못한다면, 마왕인 저희를 힘으로 소멸시킨다는 건 불가능에 수렴한답니다.</color>","JPN":"<color=#ff3636>神が作った規則を乗り越えることができないかぎり、魔王である我々を力で消滅させることは不可能に近いです。</color>","ENG":"<color=#ff3636>For if you cannot overcome the rule made by god, it is impossible for you to defeat us Demon Lords by force.</color>","TWN":"<color=#ff3636>如果不能跳出神制定的規則，靠力量消滅身為魔王的我們是不可能的。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"TWN":"<color=#ff3636>如果不能跳出神制定的規則，靠力量消滅身為魔王的我們是不可能的。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"전 당신을 쓰러뜨린다고 한 적 없어요, 에델.","JPN":"私はあなたを倒すなど言った覚えはありませんわ、エデル。","ENG":"I never said I was going to defeat you, Edel.","TWN":"我沒說過要打倒你，艾瑟兒。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"연구하겠다고 했죠.","JPN":"研究すると言いました。","ENG":"I said I was going to study you.","TWN":"我說的是研究。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네……?","JPN":"はい……？","ENG":"What...?","TWN":"嗯……？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저에게 있어 당신은 순수한 정보의 집합체.","JPN":"私にとって、あなたは純粋な情報の集合体。","ENG":"To me, you are a pure collection of information.","TWN":"對我來說，你就是單純的資訊集合體。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"날 것 그대로의 책이나 마찬가지입니다.","JPN":"本そのものと言えます。","ENG":"In other words, you are the same as a book.","TWN":"就和完完整整的書一樣。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그러니 이후로도 계속, 당신의 기만에 혹해 추종자가 될 예정은 없어요.","JPN":"ですからこれからもずっと、あなたの欺瞞に惑わされ、取り巻きになるつもりはありません。","ENG":"Also, after this time, I have no intention of succumbing to your deception and becoming a follower.","TWN":"所以，以後我也一直不打算成為受你欺騙迷惑的追隨者。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"천체의 운행으로 미래를 읽는다고 한다면, 그 원리를 증명하겠습니다.","JPN":"天体の運行で未来を読むとしたら、その原理を証明してみせましょう。","ENG":"If you say you can predict the future by the movements of the celestial bodies, I will try to prove it.","TWN":"如果你用天體的運行來預測未來，那我就證明其原理。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};